const urlString = $.input.urls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.startsWith('http'));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapeUrls.response.iterations || [];

let allContent = '';
let successCount = 0;
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : {};
  const md = resp.markdown || '';

  allContent += '=== PAGE ' + (i + 1) + ' ===\n';
  allContent += 'URL: ' + url + '\n';
  allContent += 'Content:\n' + md.slice(0, 4000) + '\n\n';
  if (md.length > 0) successCount++;
});

return { allContent, successCount, totalUrls: urls.length };

const d = $.steps.compileScraped.output;
const dataDesc = $.input.dataDescription || 'all structured data items';

let prompt = 'You are a web scraping data extraction specialist. Extract structured, tabular data from the scraped webpages below.\n\n';
prompt += 'DATA TO EXTRACT: ' + dataDesc + '\n';
prompt += 'PAGES SCRAPED: ' + d.successCount + '/' + d.totalUrls + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + d.allContent + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify repeating data patterns (products, listings, entries, table rows)\n';
prompt += '- Extract every item with all available fields\n';
prompt += '- Create consistent column headers across all items\n';
prompt += '- Normalize data types (numbers as numbers, dates in ISO format)\n';
prompt += '- Include the source URL for each item\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pageTitle": "descriptive title for the dataset",\n';
prompt += '  "itemType": "what kind of items",\n';
prompt += '  "headers": ["Column1", "Column2", "Column3", "Source URL"],\n';
prompt += '  "items": [\n';
prompt += '    { "Column1": "val", "Column2": "val", "Column3": "val", "Source URL": "url" }\n';
prompt += '  ],\n';
prompt += '  "totalItems": 0,\n';
prompt += '  "summary": "one-line description of extracted data"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pageTitle: 'Scraped Data', itemType: 'unknown', headers: ['Data'], items: [], totalItems: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const items = ai.items || [];
const headers = ai.headers || (items.length > 0 ? Object.keys(items[0]) : ['Data']);

const sheetData = items.map((item, i) => {
  const row = { '#': i + 1 };
  headers.forEach(h => { row[h] = item[h] !== undefined ? String(item[h]) : ''; });
  return row;
});

const date = new Date().toISOString().split('T')[0];

return { sheetData, itemCount: items.length, pageTitle: ai.pageTitle || 'Scraped Data', summary: ai.summary || '', date };

const ai = $.steps.parseAI.output;
const d = $.steps.buildSheetData.output;
const scraped = $.steps.compileScraped.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Web Scraping to Sheets Complete' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Pages Scraped:*\n' + scraped.successCount + '/' + scraped.totalUrls },
  { type: 'mrkdwn', text: '*Items Extracted:*\n' + d.itemCount }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Data Type:*\n' + (ai.itemType || 'unknown') },
  { type: 'mrkdwn', text: '*Sheet Title:*\n' + ($.input.sheetTitle || 'Scraped Data') }
] });
blocks.push({ type: 'divider' });

if (d.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + d.summary } });
}

const headers = ai.headers || [];
if (headers.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Columns:* ' + headers.join(', ') } });
}

const items = ai.items || [];
if (items.length > 0) {
  let preview = '*Preview (first 3 rows):*\n';
  items.slice(0, 3).forEach((item, i) => {
    const vals = headers.slice(0, 3).map(h => h + ': ' + (item[h] || '').toString().slice(0, 40));
    preview += (i + 1) + '. ' + vals.join(' | ') + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: preview.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI + Google Sheets' }] });

const fallback = 'Scraped ' + scraped.successCount + ' pages, ' + d.itemCount + ' items saved to Sheets';
return { blocks, fallback };
